const amqplib = require('amqplib');
const crypto = require('crypto');

// In production, use a proper secret management service (AWS Secrets Manager, HashiCorp Vault, etc.)
const HMAC_SECRET = process.env.PAYMENT_HMAC_SECRET;
if (!HMAC_SECRET) {
  console.error('FATAL: PAYMENT_HMAC_SECRET environment variable is required');
  process.exit(1);
}

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.PAYMENT_QUEUE || 'payment_events';
const DEAD_LETTER_QUEUE = `${QUEUE_NAME}.dlq`;
const MAX_RETRIES = 3;

// Verify HMAC signature on incoming messages
function verifyMessageSignature(messageBody, signature) {
  if (!signature) {
    return false;
  }
  const expectedSignature = crypto
    .createHmac('sha256', HMAC_SECRET)
    .update(messageBody)
    .digest('hex');
  return crypto.timingSafeEqual(
    Buffer.from(signature, 'hex'),
    Buffer.from(expectedSignature, 'hex')
  );
}

// Validate payment message schema and values
function validatePaymentMessage(payment) {
  const errors = [];

  if (!payment || typeof payment !== 'object') {
    return { valid: false, errors: ['Message is not a valid object'] };
  }

  // Required fields
  const requiredFields = ['paymentId', 'amount', 'currency', 'recipientId', 'senderId', 'timestamp'];
  for (const field of requiredFields) {
    if (payment[field] === undefined || payment[field] === null) {
      errors.push(`Missing required field: ${field}`);
    }
  }

  // Type and range checks
  if (typeof payment.amount !== 'number' || payment.amount <= 0 || payment.amount > 1000000) {
    errors.push('Amount must be a positive number up to 1,000,000');
  }

  if (!Number.isFinite(payment.amount)) {
    errors.push('Amount must be a finite number');
  }

  const allowedCurrencies = ['USD', 'EUR', 'GBP', 'CAD', 'AUD'];
  if (!allowedCurrencies.includes(payment.currency)) {
    errors.push(`Currency must be one of: ${allowedCurrencies.join(', ')}`);
  }

  const allowedTypes = ['transfer', 'refund', 'payout'];
  if (payment.type && !allowedTypes.includes(payment.type)) {
    errors.push(`Payment type must be one of: ${allowedTypes.join(', ')}`);
  }

  // Check message freshness (reject messages older than 5 minutes)
  if (payment.timestamp) {
    const messageAge = Date.now() - new Date(payment.timestamp).getTime();
    if (messageAge > 5 * 60 * 1000) {
      errors.push('Message timestamp is too old (possible replay attack)');
    }
    if (messageAge < -60 * 1000) {
      errors.push('Message timestamp is in the future');
    }
  }

  // Sanitize string fields against injection
  const stringFields = ['paymentId', 'recipientId', 'senderId'];
  const safePattern = /^[a-zA-Z0-9\-_]+$/;
  for (const field of stringFields) {
    if (payment[field] && !safePattern.test(String(payment[field]))) {
      errors.push(`Field ${field} contains invalid characters`);
    }
  }

  return { valid: errors.length === 0, errors };
}

// Idempotency tracking (use Redis or a database in production)
const processedPayments = new Map();
const IDEMPOTENCY_TTL = 24 * 60 * 60 * 1000; // 24 hours

function isAlreadyProcessed(paymentId) {
  const entry = processedPayments.get(paymentId);
  if (entry && Date.now() - entry.timestamp < IDEMPOTENCY_TTL) {
    return true;
  }
  return false;
}

function markAsProcessed(paymentId) {
  processedPayments.set(paymentId, { timestamp: Date.now() });
  // Clean up old entries periodically
  if (processedPayments.size > 10000) {
    const now = Date.now();
    for (const [key, value] of processedPayments) {
      if (now - value.timestamp > IDEMPOTENCY_TTL) {
        processedPayments.delete(key);
      }
    }
  }
}

// Payment processing logic
async function processPayment(payment) {
  console.log(`Processing payment ${payment.paymentId}: ${payment.amount} ${payment.currency} from ${payment.senderId} to ${payment.recipientId}`);

  // Simulate payment processing
  // In production, this would call your payment gateway, update database, etc.
  switch (payment.type) {
    case 'transfer':
      console.log(`Executing transfer for payment ${payment.paymentId}`);
      break;
    case 'refund':
      console.log(`Executing refund for payment ${payment.paymentId}`);
      break;
    case 'payout':
      console.log(`Executing payout for payment ${payment.paymentId}`);
      break;
    default:
      console.log(`Executing default payment for ${payment.paymentId}`);
  }

  // Simulate async processing
  await new Promise((resolve) => setTimeout(resolve, 100));

  return { success: true, paymentId: payment.paymentId };
}

async function startConsumer() {
  let connection;
  let channel;

  try {
    connection = await amqplib.connect(RABBITMQ_URL);
    channel = await connection.createChannel();

    // Set up dead letter exchange for failed messages
    await channel.assertExchange('payment_dlx', 'direct', { durable: true });
    await channel.assertQueue(DEAD_LETTER_QUEUE, { durable: true });
    await channel.bindQueue(DEAD_LETTER_QUEUE, 'payment_dlx', QUEUE_NAME);

    // Set up main queue with dead letter routing
    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-dead-letter-exchange': 'payment_dlx',
        'x-dead-letter-routing-key': QUEUE_NAME,
      },
    });

    // Process one message at a time for payment safety
    await channel.prefetch(1);

    console.log(`Payment consumer started. Listening on queue: ${QUEUE_NAME}`);

    await channel.consume(QUEUE_NAME, async (msg) => {
      if (!msg) return;

      const rawContent = msg.content.toString();
      const messageId = msg.properties.messageId || 'unknown';
      const retryCount = (msg.properties.headers && msg.properties.headers['x-retry-count']) || 0;

      console.log(`Received message ${messageId} (retry: ${retryCount})`);

      try {
        // Step 1: Verify message signature
        const signature = msg.properties.headers && msg.properties.headers['x-hmac-signature'];
        if (!verifyMessageSignature(rawContent, signature)) {
          console.error(`SECURITY: Message ${messageId} failed signature verification. Rejecting without requeue.`);
          channel.nack(msg, false, false); // Send to DLQ
          return;
        }

        // Step 2: Parse message
        let payment;
        try {
          payment = JSON.parse(rawContent);
        } catch (parseError) {
          console.error(`Message ${messageId} contains invalid JSON. Rejecting.`);
          channel.nack(msg, false, false);
          return;
        }

        // Step 3: Validate message schema and values
        const validation = validatePaymentMessage(payment);
        if (!validation.valid) {
          console.error(`Message ${messageId} validation failed:`, validation.errors);
          channel.nack(msg, false, false);
          return;
        }

        // Step 4: Idempotency check
        if (isAlreadyProcessed(payment.paymentId)) {
          console.warn(`Payment ${payment.paymentId} already processed. Acknowledging duplicate.`);
          channel.ack(msg);
          return;
        }

        // Step 5: Process the payment
        const result = await processPayment(payment);

        if (result.success) {
          markAsProcessed(payment.paymentId);
          console.log(`Payment ${payment.paymentId} processed successfully.`);
          channel.ack(msg);
        } else {
          throw new Error(`Payment processing returned failure for ${payment.paymentId}`);
        }
      } catch (error) {
        console.error(`Error processing message ${messageId}:`, error.message);

        if (retryCount < MAX_RETRIES) {
          // Requeue with incremented retry count
          console.log(`Retrying message ${messageId} (attempt ${retryCount + 1}/${MAX_RETRIES})`);
          const headers = { ...msg.properties.headers, 'x-retry-count': retryCount + 1 };
          channel.publish('', QUEUE_NAME, msg.content, {
            ...msg.properties,
            headers,
          });
          channel.ack(msg);
        } else {
          console.error(`Message ${messageId} exceeded max retries. Sending to DLQ.`);
          channel.nack(msg, false, false);
        }
      }
    });

    // Handle connection errors
    connection.on('error', (err) => {
      console.error('RabbitMQ connection error:', err.message);
    });

    connection.on('close', () => {
      console.error('RabbitMQ connection closed. Attempting reconnect in 5s...');
      setTimeout(startConsumer, 5000);
    });
  } catch (error) {
    console.error('Failed to start consumer:', error.message);
    if (channel) await channel.close().catch(() => {});
    if (connection) await connection.close().catch(() => {});
    console.log('Retrying in 5 seconds...');
    setTimeout(startConsumer, 5000);
  }
}

// Graceful shutdown
process.on('SIGINT', async () => {
  console.log('Shutting down payment consumer...');
  process.exit(0);
});

process.on('SIGTERM', async () => {
  console.log('Shutting down payment consumer...');
  process.exit(0);
});

startConsumer();

// --- Helper: Example publisher showing how to sign messages ---
// This would be in a separate service
async function examplePublisher() {
  const connection = await amqplib.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();

  const payment = {
    paymentId: 'pay_abc123',
    type: 'transfer',
    amount: 99.99,
    currency: 'USD',
    senderId: 'user_001',
    recipientId: 'user_002',
    timestamp: new Date().toISOString(),
  };

  const messageBody = JSON.stringify(payment);
  const signature = crypto
    .createHmac('sha256', HMAC_SECRET)
    .update(messageBody)
    .digest('hex');

  channel.sendToQueue(QUEUE_NAME, Buffer.from(messageBody), {
    persistent: true,
    messageId: `msg_${Date.now()}`,
    headers: {
      'x-hmac-signature': signature,
    },
  });

  console.log('Published signed payment message');
  await channel.close();
  await connection.close();
}

